{
  "schema_version": 1,
  "request_id": "rf-suggest-edit-heater-multi-action-001",
  "project": "radishflow",
  "task": "suggest_flowsheet_edits",
  "status": "ok",
  "requires_confirmation": true,
  "answers": [
    {
      "summary": "当前围绕选中的进料流 feed-1 与加热器 heater-1 的缺失规格问题生成候选补全提案：进料流缺少流量规格，加热器在出口温度控制模式下缺少出口温度目标。",
      "issues": [
        {
          "title": "Cold Feed 缺少流量规格",
          "description": "诊断指出流股 feed-1 缺少 flow rate specification；该流股当前仅包含 temperature_c 与 pressure_kpa，尚无流量相关规格。",
          "severity": "error",
          "target": {
            "type": "stream",
            "id": "feed-1"
          },
          "citations": [
            "diag-1",
            "flowdoc-stream-1"
          ]
        },
        {
          "title": "Feed Heater 缺少出口温度控制目标",
          "description": "诊断指出单元 heater-1 配置为 outlet_temperature 控制模式，但缺少 outlet temperature target；当前配置中仅有 control_mode。",
          "severity": "error",
          "target": {
            "type": "unit",
            "id": "heater-1"
          },
          "citations": [
            "diag-2",
            "flowdoc-unit-1"
          ]
        }
      ],
      "proposed_actions": [
        {
          "action": "candidate_edit",
          "title": "为 Cold Feed 添加流量规格占位",
          "target": {
            "type": "stream",
            "id": "feed-1"
          },
          "rationale": "该提案仅在被诊断直接指向的流股 feed-1 上添加一个待确认的流量规格占位，用于提示用户补齐求解所需的进料流量；不假定具体数值或单位。",
          "patch": {
            "spec_placeholders": {
              "flow_rate": {
                "required": true,
                "reason": "Cold Feed is missing flow rate specification.",
                "suggested_by_diagnostic": "STREAM_SPEC_MISSING"
              }
            }
          },
          "risk_level": "medium",
          "requires_confirmation": true,
          "citations": [
            "diag-1",
            "flowdoc-stream-1"
          ]
        },
        {
          "action": "candidate_edit",
          "title": "为 Feed Heater 添加出口温度目标占位",
          "target": {
            "type": "unit",
            "id": "heater-1"
          },
          "rationale": "该提案仅在已配置为 outlet_temperature 控制模式的加热器 heater-1 上添加出口温度目标占位，提示用户确认目标值；不更改控制模式、连接关系或拓扑。",
          "patch": {
            "parameter_placeholders": {
              "outlet_temperature_target": {
                "required": true,
                "reason": "Feed Heater is configured for outlet temperature control but outlet temperature target is missing.",
                "suggested_by_diagnostic": "UNIT_PARAMETER_INCOMPLETE"
              }
            }
          },
          "risk_level": "medium",
          "requires_confirmation": true,
          "citations": [
            "diag-2",
            "flowdoc-unit-1"
          ]
        }
      ],
      "confidence": 0.91
    }
  ]
}
